/* 现代前端开发中，抛弃 border="1" cellspacing="0" 等写法，直接用CSS控制： */

table {
  width: 100%; /* 替代表格的 width="100%" */
  border-collapse: collapse; /* 替代 cellspacing="0"，合并双边框为单实线 */
  border: 1px solid #ccc; /* 给外框加线 */
}

th, td {
  padding: 12px; /* 替代 cellpadding="12"，设置舒服的内边距 */
  border: 1px solid #ccc; /* 给每个内部单元格加线 */
  text-align: center; /* 替代 align="center" 水平居中 */
  vertical-align: middle; /* 替代 valign="middle" 垂直居中 */
}

/* 核心重置，消灭丑陋的双线缝隙 */
.emp-table {
  width: 80%;
  margin: 20px auto;
  border-collapse: collapse;
  font-family: sans-serif;
}

/* 统一定义边框和内边距 */
.emp-table th, .emp-table td {
  border: 1px solid #ddd;
  padding: 12px 15px;
  text-align: center;
}

/* 表头高级定制 */
.emp-table thead tr:first-child th {
  background-color: #0d1b4b;
  color: #fff;
  font-size: 1.2rem;
}

/* 数据行悬停高亮提示效果（提升体验的神来之笔） */
.emp-table tbody tr:hover {
  background-color: #f1f8ff;
}
